parameters.message:
={{ (() => {
  const b = $json.body;
  const BRAND = '#7d1c34';
  const SIG = '#A72231';
  const name = b.full_name ? b.full_name : '';
  const greeting = name ? ('Bonjour ' + name + ' 👋,') : 'Bonjour 👋,';
  const labels = { setup: 'Définir mon mot de passe', reset: 'Réinitialiser mon mot de passe' };
  const btnLabel = labels[b.kind];
  const hasBtn = b.link && btnLabel;
  let body;
  if (b.kind === 'setup') {
    body = '<p style="margin:0 0 8px;font-size:20px;font-weight:800;color:' + BRAND + ';">Bienvenue chez Fingec ! 🎉</p>'
      + '<p style="margin:0 0 12px;">Toute l\'équipe est ravie de vous compter parmi nous. ✨</p>'
      + '<p style="margin:0 0 4px;">Votre compte vient d\'être créé sur l\'espace comptabilité Fingec. Il ne reste plus qu\'une étape pour y accéder : définir votre mot de passe en cliquant sur le bouton ci-dessous. 🔐</p>';
  } else {
    body = '<p style="margin:0 0 4px;">' + b.intro + '</p>';
  }
  const button = hasBtn ? ('<table role="presentation" cellpadding="0" cellspacing="0" style="margin:24px 0;"><tr><td style="border-radius:8px;background:' + BRAND + ';"><a href="' + b.link + '" style="display:inline-block;padding:13px 26px;font-family:\'Segoe UI\',Arial,sans-serif;font-size:15px;font-weight:600;color:#ffffff;text-decoration:none;border-radius:8px;">' + btnLabel + '</a></td></tr></table>') : '';
  const fallback = hasBtn ? ('<p style="font-size:12px;color:#888;line-height:1.5;">Si le bouton ne fonctionne pas, copiez-collez ce lien dans votre navigateur :<br><a href="' + b.link + '" style="color:' + BRAND + ';">' + b.link + '</a></p><p style="font-size:12px;color:#888;">Ce lien est valable 1 heure. ⏳</p>') : '';
  const sig = '<table cellpadding="0" cellspacing="0" style="border-collapse:collapse;border-top:2px solid ' + SIG + ';padding-top:12px;font-family:\'Segoe UI\',Arial,sans-serif;margin-top:16px;">'
    + '<tr>'
    + '<td style="vertical-align:top;padding:12px 16px 0 0;"><img src="https://raw.githubusercontent.com/fingec/fingec-assets/refs/heads/main/fing.png" width="88" alt="Fingec" style="display:block;"></td>'
    + '<td style="vertical-align:top;padding-top:12px;line-height:1.5;">'
    + '<div style="font-size:18px;font-weight:700;color:' + SIG + ';">Cabinet Fingec</div>'
    + '<div style="font-size:13px;color:' + SIG + ';">Cabinet Fingec</div>'
    + '<div style="font-size:12px;color:#555;">12 rue Exemple, 67000 Strasbourg</div>'
    + '<div style="font-size:12px;color:#444;">Cabinet membre de l\'Ordre des Experts-Comptables d\'Alsace</div>'
    + '<div style="font-size:12px;color:' + SIG + ';">contact@fingec.fr | www.fingec.fr</div>'
    + '</td></tr></table>';
  return '<div style="background:#f4f4f5;padding:24px 0;font-family:\'Segoe UI\',Arial,sans-serif;">'
    + '<table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td align="center">'
    + '<table role="presentation" width="560" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:14px;overflow:hidden;border:1px solid #ececec;">'
    + '<tr><td style="background:' + BRAND + ';padding:22px 32px;"><img src="https://raw.githubusercontent.com/fingec/fingec-assets/refs/heads/main/fing.png" width="95" alt="Fingec" style="display:block;"></td></tr>'
    + '<tr><td style="padding:32px;color:#333;font-size:14px;line-height:1.65;">'
    + '<p style="margin:0 0 14px;font-size:16px;color:#1a1a1a;">' + greeting + '</p>'
    + body + button + fallback
    + '<p style="margin:18px 0 0;">Cordialement,</p>'
    + sig
    + '</td></tr>'
    + '<tr><td style="background:#faf7f8;padding:14px 32px;border-top:1px solid #eee;"><p style="margin:0;font-size:11px;color:#999;">Cet e-mail vous est adressé car un compte vous concernant a été créé ou modifié sur l\'espace Fingec. Si vous n\'êtes pas concerné, ignorez ce message.</p></td></tr>'
    + '</table></td></tr></table></div>';
})() }}
